#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
int main()
{
//	FIN("data.in");FOUT("mine.out");
	int r;scanf("%d",&r);
	while(!(r&1))r>>=1;if(r==1)return puts("4"),0;
	long long ans=1;
	for(int j=3;j*j<=r;++j)if(r%j==0)
	{
		int cnt=0;do ++cnt,r/=j;while(r%j==0);
		
		if((j&3)==1)ans*=cnt<<1|1;
	}
	if((r&3)==1&&r!=1)ans*=3;printf("%lld\n",ans<<2);
}
